import ratedR from "../assets/rated-r.png";
import ratedPG13 from "../assets/rated-pg-13.png";
import ratedPG from "../assets/rated-pg.png";
import ratedG from "../assets/rated-g.png";


function MovieCard({ title, rating, release, genre, runtime, poster, writer, director, myRating }) {
    const ratingSrc = () => {
        if (rating === "R") {
            return ratedR
        } else if (rating === "PG-13") {
            return ratedPG13
            }
        }

    return (
        <div>
            <div className="max-w-xs bg-white rounded-lg shadow m-10">
                <a href="#">
                    <img className="rounded-t-lg" src={poster} alt={title} />
                </a>
                <div className="p-5">
                    <a href="#">
                        <h5 className="mb-2 text-3xl font-bold tracking-tight text-black">{title}</h5>
                    </a>
                    <div>
                        <img className="" src={ratingSrc} />
                        <p className="inline font-normal text-gray-700">{runtime}</p>
                    </div>
                    <p className="font-normal text-gray-700">{writer}, writer</p>
                    <p className="mb-3 font-normal text-gray-700">{director}, director</p>
                    <span className="me-2 mb-2 inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">
                        {genre.genre1}
                    </span>
                    <span className="me-2 mb-2 inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">
                        {genre.genre2}
                    </span>
                    <span className="inline-flex items-center px-3 py-2 text-xs font-medium text-center text-white bg-sky-700 rounded-lg">
                        {genre.genre3}
                    </span>
                </div>
            </div>
        </div>
    )
}

export default MovieCard;
